from flask import Flask, jsonify, request
from flask_jwt_extended import JWTManager, create_access_token, jwt_required, get_raw_jwt
from passlib.hash import sha256_crypt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
jwt = JWTManager(app)

users = {
    "user1": {"password": sha256_crypt.hash("password1")},
    "user2": {"password": sha256_crypt.hash("password2")}
}

@app.route('/register', methods=['POST'])
def register():
    if request.json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']
        if username not in users:
            users[username] = {"password": sha256_crypt.hash(password)}
            return jsonify({"message": f"User {username} registered!"}), 201
        else:
            return jsonify({"error": "Username already exists."}), 400
    else:
        return jsonify({"error": "Invalid payload."}), 400

@app.route('/login', methods=['POST'])
def login():
    if request.json and 'username' in request.json and 'password' in request.json:
        username = request.json['username']
        password = request.json['password']
        if username in users and sha256_crypt.verify(password, users[username]["password"]):
            access_token = create_access_token(identity=username)
            return jsonify({"access_token": access_token})
        else:
            return jsonify({"error": "Invalid credentials."}), 401
    else:
        return jsonify({"error": "Invalid payload."}), 400

@app.route('/protected', methods=['GET'])
@jwt_required()
def protected():
    return jsonify({"message": "This is a protected resource."})

if __name__ == '__main__':
    app.run(debug=True)